    if paper['venue'] == 'CHI':
        chi_papers[paper['title']] = paper

chi_citations_2020 = []
for citation in citations_2020:
    citation_title = citation.get('title', '')
    if citation_title in chi_papers:
        chi_citations_2020.append({
            'title': citation_title,
            'citation_count': int(citation.get('citation_count', 0))
        })

total_citations = sum(c['citation_count'] for c in chi_citations_2020)

print('__RESULT__:')
print(json.dumps({
    'total_chi_citations_2020': total_citations,
    'num_chi_papers_cited': len(chi_citations_2020)
}))"}

{"code": "import json

citations_file_path = locals()['var_functions.query_db:7']
with open(citations_file_path, 'r') as f:
    citations_2020 = json.load(f)

paper_docs_file_path = locals()['var_functions.query_db:14']
with open(paper_docs_file_path, 'r') as f:
    paper_docs = json.load(f)

# Create a mapping of titles to check which CHI papers we found
paper_titles = [doc.get('filename', '').replace('.txt', '') for doc in paper_docs]

print('Paper titles in database:')
for title in paper_titles:
    print(f'  - {title}')

print('\nCHI citations in 2020:')
chi_citations = []
for citation in citations_2020:
    citation_title = citation.get('title', '')
    if citation_title in paper_titles:
        # Check if it's actually a CHI paper by looking at the text
        for doc in paper_docs:
            if doc.get('filename', '').replace('.txt', '') == citation_title:
                text = doc.get('text', '')
                if 'CHI' in text:
                    chi_citations.append({
                        'title': citation_title,
                        'citations': int(citation.get('citation_count', 0))
                    })
                    print(f"  - {citation_title}: {citation.get('citation_count')} citations")

print(f'\nTotal CHI citations in 2020: {sum(c["citations"] for c in chi_citations)}')
print(f'Number of CHI papers cited: {len(chi_citations)}')

print('__RESULT__:')
print(json.dumps({
    'total_citations': sum(c['citations'] for c in chi_citations),
    'paper_count': len(chi_citations),
    'papers': chi_citations
}))"}

